Code.NativeIaC:
```bicep
// Bicep: AKS cluster with Azure Monitor (Container Insights) enabled
resource aks 'Microsoft.ContainerService/managedClusters@2024-02-01' = {
  name: '<example_resource_name>'
  location: resourceGroup().location
  properties: {
    addonProfiles: {
      omsagent: {
        enabled: true // CRITICAL: enables Azure Monitor / Container Insights
        config: {
          logAnalyticsWorkspaceResourceID: '<log_analytics_workspace_resource_id>'
        }
      }
    }
  }
}
```

Code.Terraform:
```hcl
# Terraform: AKS cluster with Azure Monitor (Container Insights) enabled
resource "azurerm_kubernetes_cluster" "<example_resource_name>" {
  name                = "<example_resource_name>"
  location            = "<region>"
  resource_group_name = "<example_resource_name>"
  dns_prefix          = "<example_resource_name>"

  oms_agent {
    log_analytics_workspace_id = "<log_analytics_workspace_resource_id>" # CRITICAL: enables Azure Monitor / Container Insights
  }
}
```
